def valid_ids(ids, divisor):
    result = []
    for num in ids:
        digit_sum = 0
        for ch in str(num):
            digit_sum += int(ch)
        if digit_sum % divisor == 0:
            result.append(num)
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_divisor_3(self):
        self.assertEqual(valid_ids([123, 456, 789, 100], 3), [123, 456, 789])

    def test_all_valid(self):
        self.assertEqual(valid_ids([55, 19, 28, 37], 10), [55, 19, 28, 37])

    def test_none_valid(self):
        self.assertEqual(valid_ids([11, 22, 33, 44], 5), [])

    def test_hidden_empty_list(self):
        self.assertEqual(valid_ids([], 3), [])

    def test_hidden_single_element_valid(self):
        self.assertEqual(valid_ids([9], 9), [9])

    def test_hidden_zero_id(self):
        self.assertEqual(valid_ids([0], 1), [0])

    def test_hidden_large_number(self):
        self.assertEqual(valid_ids([99999], 9), [99999])

    def test_hidden_even_digit_sums(self):
        self.assertEqual(valid_ids([10, 20, 30, 40, 50], 2), [20, 40])

    def test_hidden_divisor_1_all_pass(self):
        self.assertEqual(valid_ids([1, 23, 456, 7890], 1), [1, 23, 456, 7890])

    def test_hidden_mixed(self):
        self.assertEqual(valid_ids([14, 23, 50, 77, 100], 5), [14, 23, 50])

if __name__ == '__main__':
    unittest.main()
